// ============================================================
// P0: Merge Strategy Logic (Pure Unit Tests)
// ============================================================
describe('[P0] Merge strategy -- department name deduplication', () => {
  test('skip department when name already exists', () => {
    const existing = new Set(['재무팀'])
    const template = INVESTMENT_TEMPLATE
    let created = 0, skipped = 0
    for (const dept of template.departments) {
      if (existing.has(dept.name)) skipped++
      else created++
    }
    expect(skipped).toBe(1)
    expect(created).toBe(0)
  })

  test('create department when name does not exist', () => {
    const existing = new Set(['인사팀'])
    const template = INVESTMENT_TEMPLATE
    let created = 0, skipped = 0
    for (const dept of template.departments) {
      if (existing.has(dept.name)) skipped++
      else created++
    }
    expect(created).toBe(1)
    expect(skipped).toBe(0)
  })

  test('all-in-one: partial overlap creates only missing depts', () => {
    const existing = new Set(['개발팀', '재무팀'])
    const template = ALL_IN_ONE_TEMPLATE
    let created = 0, skipped = 0
    for (const dept of template.departments) {
      if (existing.has(dept.name)) skipped++
      else created++
    }
    expect(skipped).toBe(2) // 개발팀, 재무팀
    expect(created).toBe(2) // 경영지원실, 마케팅팀
  })
})

describe('[P0] Merge strategy -- agent name deduplication', () => {
  test('skip agent when name already exists in company', () => {
    const existingAgents = new Set(['CIO', '투자분석 전문가 A'])
    const agents = INVESTMENT_TEMPLATE.departments[0].agents
    let created = 0, skipped = 0
    for (const a of agents) {
      if (existingAgents.has(a.name)) skipped++
      else created++
    }
    expect(skipped).toBe(2)
    expect(created).toBe(3)
  })

  test('create all agents when none exist', () => {
    const existingAgents = new Set<string>()
    const agents = MARKETING_TEMPLATE.departments[0].agents
    let created = 0
    for (const a of agents) {
      if (!existingAgents.has(a.name)) created++
    }
    expect(created).toBe(4)
  })

  test('skip all agents when all names exist', () => {
    const names = INVESTMENT_TEMPLATE.departments[0].agents.map(a => a.name)
    const existingAgents = new Set(names)
    let skipped = 0
    for (const a of INVESTMENT_TEMPLATE.departments[0].agents) {
      if (existingAgents.has(a.name)) skipped++
    }
    expect(skipped).toBe(5)
  })
})

// ============================================================
// P1: Combined Merge Simulation
// ============================================================
describe('[P1] Full merge simulation', () => {
  test('apply marketing template to company with existing CMO agent', () => {
    const existingDepts = new Set<string>()
    const existingAgents = new Set(['CMO'])
    const template = MARKETING_TEMPLATE
    let dc = 0, ds = 0, ac = 0, as2 = 0
    for (const dept of template.departments) {
      if (existingDepts.has(dept.name)) ds++
      else dc++
      for (const a of dept.agents) {
        if (existingAgents.has(a.name)) as2++
        else ac++
      }
    }
    expect(dc).toBe(1)
    expect(ds).toBe(0)
    expect(ac).toBe(3) // 콘텐츠 전문가, SNS 전문가, 디자인 워커
    expect(as2).toBe(1) // CMO
  })

  test('apply all-in-one to fully populated company', () => {
    const template = ALL_IN_ONE_TEMPLATE
    const allDeptNames = new Set(template.departments.map(d => d.name))
    const allAgentNames = new Set(template.departments.flatMap(d => d.agents.map(a => a.name)))

    let dc = 0, ds = 0, ac = 0, as2 = 0
    for (const dept of template.departments) {
      if (allDeptNames.has(dept.name)) ds++
      else dc++
      for (const a of dept.agents) {
        if (allAgentNames.has(a.name)) as2++
        else ac++
      }
    }
    expect(dc).toBe(0)
    expect(ds).toBe(4)
    expect(ac).toBe(0)
    expect(as2).toBe(12)
  })

  test('department skipped but agents still created under it', () => {
    // Scenario: 재무팀 exists but none of its agents do
    const existingDepts = new Map([['재무팀', 'existing-dept-id']])
    const existingAgents = new Set<string>()
    const template = INVESTMENT_TEMPLATE

    const details: Array<{ dept: string; action: string; agentsCreated: number }> = []
    for (const dept of template.departments) {
      const deptAction = existingDepts.has(dept.name) ? 'skipped' : 'created'
      let agentsCreated = 0
      for (const a of dept.agents) {
        if (!existingAgents.has(a.name)) agentsCreated++
      }
      details.push({ dept: dept.name, action: deptAction, agentsCreated })
    }

    expect(details[0].action).toBe('skipped')
    expect(details[0].agentsCreated).toBe(5) // All 5 agents created under existing dept
  })
})

