describe('[P1] Template agent data completeness', () => {
  const allTemplates = [INVESTMENT_TEMPLATE, MARKETING_TEMPLATE, ALL_IN_ONE_TEMPLATE]

  test('all agents have non-empty name', () => {
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          expect(agent.name.length).toBeGreaterThan(0)
        }
      }
    }
  })

  test('all agents have valid tier', () => {
    const validTiers = ['manager', 'specialist', 'worker']
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          expect(validTiers).toContain(agent.tier)
        }
      }
    }
  })

  test('all agents have valid modelName', () => {
    const validModels = ['claude-sonnet-4-6', 'claude-haiku-4-5']
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          expect(validModels).toContain(agent.modelName)
        }
      }
    }
  })

  test('managers always use sonnet model', () => {
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          if (agent.tier === 'manager') {
            expect(agent.modelName).toBe('claude-sonnet-4-6')
          }
        }
      }
    }
  })

  test('non-managers use haiku model', () => {
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          if (agent.tier !== 'manager') {
            expect(agent.modelName).toBe('claude-haiku-4-5')
          }
        }
      }
    }
  })

  test('all agents have non-empty soul with Korean text', () => {
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          expect(agent.soul.length).toBeGreaterThan(10)
          expect(agent.soul).toMatch(/[\uAC00-\uD7A3]/)
        }
      }
    }
  })

  test('all agents have at least one allowed tool', () => {
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          expect(agent.allowedTools.length).toBeGreaterThan(0)
        }
      }
    }
  })

  test('all agents have non-empty role', () => {
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          expect(agent.role.length).toBeGreaterThan(0)
        }
      }
    }
  })

  test('all departments have non-empty description', () => {
    for (const tmpl of allTemplates) {
      for (const dept of tmpl.departments) {
        expect(dept.description.length).toBeGreaterThan(0)
      }
    }
  })
})

