describe('[P2] Edge cases -- template data serialization', () => {
  test('JSON round-trip preserves investment template', () => {
    const json = JSON.stringify(INVESTMENT_TEMPLATE)
    const parsed = JSON.parse(json) as TemplateData
    expect(parsed.departments).toHaveLength(1)
    expect(parsed.departments[0].agents).toHaveLength(5)
    expect(parsed.departments[0].agents[0].name).toBe(INVESTMENT_TEMPLATE.departments[0].agents[0].name)
  })

  test('JSON round-trip preserves all-in-one template', () => {
    const json = JSON.stringify(ALL_IN_ONE_TEMPLATE)
    const parsed = JSON.parse(json) as TemplateData
    expect(parsed.departments).toHaveLength(4)
    const totalAgents = parsed.departments.reduce((s, d) => s + d.agents.length, 0)
    expect(totalAgents).toBe(12)
  })

  test('template data handles special characters in soul', () => {
    for (const tmpl of [INVESTMENT_TEMPLATE, MARKETING_TEMPLATE, ALL_IN_ONE_TEMPLATE]) {
      for (const dept of tmpl.departments) {
        for (const agent of dept.agents) {
          // Ensure soul can be JSON serialized and deserialized
          const json = JSON.stringify({ soul: agent.soul })
          const parsed = JSON.parse(json)
          expect(parsed.soul).toBe(agent.soul)
        }
      }
    }
  })
})

describe('[P2] Edge cases -- empty and boundary conditions', () => {
  test('empty existing sets mean full creation', () => {
    const existingDepts = new Set<string>()
    const existingAgents = new Set<string>()
    const template = ALL_IN_ONE_TEMPLATE

    let totalCreated = 0
    for (const dept of template.departments) {
      if (!existingDepts.has(dept.name)) totalCreated++
      for (const a of dept.agents) {
        if (!existingAgents.has(a.name)) totalCreated++
      }
    }
    expect(totalCreated).toBe(16) // 4 depts + 12 agents
  })

  test('summary detail action field values are valid', () => {
    const validActions: Array<'created' | 'skipped'> = ['created', 'skipped']
    const detail: orgService.TemplateApplySummary['details'][number] = {
      departmentName: 'test',
      action: 'created',
      departmentId: 'id',
      agentsCreated: [],
      agentsSkipped: [],
    }
    expect(validActions).toContain(detail.action)

    detail.action = 'skipped'
    expect(validActions).toContain(detail.action)
  })

  test('template with duplicate agent names across departments', () => {
    // All-in-one has CMO in 마케팅팀 -- check uniqueness tracking
    const allNames = ALL_IN_ONE_TEMPLATE.departments.flatMap(d => d.agents.map(a => a.name))
    const uniqueNames = new Set(allNames)
    // CMO appears in 마케팅팀
    // Check if any name is duplicated across departments
    const hasDupes = allNames.length !== uniqueNames.size
    // This is valid -- the merge strategy handles it by tracking globally
    if (hasDupes) {
      expect(allNames.length).toBeGreaterThan(uniqueNames.size)
    } else {
      expect(allNames.length).toBe(uniqueNames.size)
    }
  })
})

